INSERT INTO t_p67171637_yug_transfer_prize_l.bot_daily_posts (photo_url, greeting, description) VALUES
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/59a70e5e-35ea-46b5-a784-a92f1d8e362a.jpg', '🚕 Лето, солнце, подсолнухи — и дорога зовёт!', 'Поездки по Краснодарскому краю с ветерком и настроением.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/30e4b599-bc38-4bc8-a717-c8aa14d6a125.jpg', '🚕 Трансфер до санатория или спа-отеля.', 'Отдых начинается с комфортной дороги. Довезём до двери.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/6bcb02fc-3256-4a6c-9205-d6ed69bdd181.jpg', '🚕 Ранний рейс? Мы заберём вас даже в 4 утра!', 'Пунктуальность — наше главное правило.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/8c6d3af9-3cdf-4124-9603-d44973c095ca.jpg', '🚕 Винные туры по Кубани — с трансфером от нас!', 'Довезём до лучших виноделен региона и обратно.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/0b9f57a2-69ec-47b0-920d-efa7bd8493d7.jpg', '🚕 По Краснодару и за его пределы!', 'Городские поездки и межгород — всё в одном сервисе.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/7ad65d57-9e6d-4d8e-bfc9-ce8d60ef7d6f.jpg', '🚕 Живописные дороги юга — наслаждайтесь поездкой!', 'Мы не просто везём, мы дарим впечатления.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/1f89bc7e-ed3b-40e0-a282-fc3486e105a6.jpg', '🚕 Экскурсии к водопадам и природным красотам!', 'Трансфер к самым красивым местам Кавказа.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/5734a0c6-1415-4511-9576-20e903d9efbb.jpg', '🚕 На рынок за свежими фруктами? Подвезём!', 'Короткие поездки по городу — быстро и недорого.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/78dc4541-eee8-40e5-b5e7-00055165e199.jpg', '🚕 Дальняя дорога? С нами она пролетит незаметно!', 'Комфортные авто для долгих поездок. Wi-Fi, зарядки, вода.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/b67a7eee-dbb2-4a2b-8485-0ca8b9184834.jpg', '🚕 Трансфер на горнолыжный курорт!', 'Красная Поляна, Архыз, Домбай — довезём с комфортом.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/6caba6a0-e31e-48cd-a8ea-0b8add8da346.jpg', '🚕 Весна — идеальное время для путешествий!', 'Закажите трансфер и наслаждайтесь цветущим югом.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/500408f6-c22d-4ecf-ad5f-ae61a3c1d018.jpg', '🚕 Свадьба, юбилей, торжество? Подадим лучший авто!', 'Украшение авто по запросу. Сделаем ваш день особенным.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/bc876769-08fb-4dae-9142-5e44b147ac0c.jpg', '🚕 Дождь — не повод отменять планы!', 'Тёплый салон, аккуратный водитель. Доберётесь сухими.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/eeb7ccd4-6632-4d19-81cd-05b48b9fed75.jpg', '🚕 Семейный выходной? Отвезём куда захотите!', 'Аквапарк, зоопарк, дельфинарий — весело и без забот.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/4a28d156-2b0a-4f40-ac23-693681f1d5d9.jpg', '🚕 Вечерняя поездка вдоль моря — бесценно!', 'Закажите трансфер и насладитесь закатом в дороге.');